#include <stdio.h>
#include <limits.h>

#define MAX_HOLES 10

int bestFit(int holes[], int n, int processSize) {
    int bestIdx = -1;
    int minDiff = INT_MAX;

    for (int i = 0; i < n; i++) {
        if (holes[i] >= processSize) {
            int diff = holes[i] - processSize;
            if (diff < minDiff) {
                minDiff = diff;
                bestIdx = i;
            }
        }
    }

    if (bestIdx != -1) {
        // Allocate and update hole
        holes[bestIdx] -= processSize;
    }

    return bestIdx;
}

void printHoles(int holes[], int n) {
    printf("Holes: ");
    for (int i = 0; i < n; i++) {
        printf("%dKB ", holes[i]);
    }
    printf("\n");
}

int main() {
    int holes[] = {300, 200, 500, 150, 400};
    int processes[] = {210, 180, 320, 100};
    int n = 5, p = 4;

    printf("Initial ");
    printHoles(holes, n);

    for (int i = 0; i < p; i++) {
        int idx = bestFit(holes, n, processes[i]);
        if (idx != -1) {
            printf("Process %dKB: Allocated at hole %d\n", 
                   processes[i], idx);
            printf("After ");
            printHoles(holes, n);
        } else {
            printf("Process %dKB: Cannot be allocated\n", processes[i]);
        }
    }

    return 0;
}
